import 'package:isar/isar.dart'; import 'package:path_provider/path_provider.dart'; part 'isar_service.g.dart'; @collection class PendingOrder { Id id = Isar.autoIncrement; late String payload; late DateTime createdAt; } class IsarService { static late Isar db; static Future<void> init() async { final dir = await getApplicationDocumentsDirectory(); db = await Isar.open([PendingOrderSchema], directory: dir.path); } static Future<void> enqueue(String json) async { await db.writeTxn(() => db.pendingOrders.put(PendingOrder()..payload = json..createdAt = DateTime.now())); } static Future<List<PendingOrder>> getPending() => db.pendingOrders.where().findAll(); static Future<void> clear(int id) => db.writeTxn(() => db.pendingOrders.delete(id)); static Future<void> syncAll(Future<String> Function(String) sendFn) async { final pending = await getPending(); for (final p in pending) { try { await sendFn(p.payload); await clear(p.id); } catch (_) {} } } }
